<script setup lang="ts">import type { BpmBusinessObjectField } from '#/api/system/bpm';import { ElCheckbox,ElCheckboxGroup,ElFormItem,ElOption,ElSelect } from 'element-plus';defineProps<{workingFields:BpmBusinessObjectField[]}>();const model=defineModel<{editableFields:string[];mode:'FIELD_CONTROLLED'|'LOCKED'}>({required:true});</script><template><ElFormItem label="审批过程中是否允许修改"><ElSelect v-model="model.mode"><ElOption label="全部只读" value="LOCKED"/><ElOption label="按字段开放" value="FIELD_CONTROLLED"/></ElSelect></ElFormItem><ElFormItem v-if="model.mode==='FIELD_CONTROLLED'" label="审批人可修改字段"><ElCheckboxGroup v-model="model.editableFields"><ElCheckbox v-for="field in workingFields" :key="field.key" :label="field.label" :value="field.key"/></ElCheckboxGroup></ElFormItem></template>
